const raw = $input.first().json;
const input = Array.isArray(raw) ? raw[0] : raw;

const sessionId = String(
  input.sessionId ||
  input.body?.sessionId ||
  input.chat?.sessionId ||
  input.metadata?.sessionId ||
  "test-sem-session"
);

const chatInput = String(
  input.chatInput ??
  input.message ??
  input.text ??
  input.body?.chatInput ??
  ""
).trim();

function phoneFromSessionId(value) {
  const raw = String(value || "");

  // Pega apenas números do sessionId e usa os 18 primeiros.
  // Resultado final sempre: 99 + 18 dígitos = 20 caracteres.
  let digits = raw.replace(/\D/g, "");

  digits = digits.padEnd(18, "0").slice(0, 18);

  return `99${digits}`;
}

const phone = phoneFromSessionId(sessionId);

if (!/^99\d{18}$/.test(phone) || phone.length !== 20) {
  throw new Error(`phone_teste_invalido: esperado 20 caracteres começando com 99, recebido ${phone}`);
}

const nowIso = new Date().toISOString();
const currentMessageId = Number(input.message_id || input.messageId || Date.now());

// Fonte única dos cães.
// Nada de campo solto tipo cao_nome, cao_raca, cao_sexo etc.
const caesJson = Array.isArray(input.caes_json)
  ? input.caes_json
  : [];

const resumoLead = {
  tutor_nome: "",
  tutor_telefone: phone,
  email_tutor: "",

  unidade_preferida: "nao_definida",
  servico_interesse: "nao_definido",
  periodo_desejado: "",
  data_desejada: "",
  data_checkin_desejada: "",
  data_checkout_desejada: "",

  origem_lead: "anuncio_whatsapp",
  origem_detalhada: "chat_n8n_teste",

  comprovante_recebido: false,
  tipo_comprovante: "nao_informado",
  arquivo_comprovante_referencia: "",
  data_hora_avaliacao: "",
  data_hora_pre_reserva: "",
  pre_reserva_criada: false,
  responsavel_humano: "",
  observacoes: ""
};

const chatHistoryUuid = `test:bruna:session:${sessionId}:phone:${phone}`.slice(0, 100);

return [
  {
    json: {
      run_mode: "sandbox",
      origem_execucao: "chat_n8n_teste",
      action: input.action || "sendMessage",
      sessionId,
      chatInput,

      lead: {
        phone,
        chat_history_uuid: chatHistoryUuid
      },

      chatwoot: {
        account_id: 990001,
        inbox_id: 990001,
        conversation_id: Number(String(phone).slice(-9)),
        contact_id: Number(String(phone).slice(-8)),
        message_id: currentMessageId,
        labels: ["teste-bruna", "chat-n8n"],
        event: "message_created",
        system_event: "MESSAGE_RECEIVED"
      },

      message: {
        content: chatInput,
        message_modality: "text_only",
        has_text: chatInput.length > 0,
        has_attachment: false,
        data_url: "",
        current_message_id: currentMessageId,
        history_for_crm: "",
        last_bruna_message_before_current_block: ""
      },

      inputs: {
        is_first_turn: true,
        caes_json: caesJson,
        quantidade_caes: caesJson.length,

        precisa_responder_preco: false,
        precisa_responder_localizacao: false,
        precisa_responder_visita_material: false,
        deve_priorizar_base_conhecimento: false,

        resumo_lead: resumoLead
      },

      memory: {
        phone,
        chat_history_uuid: chatHistoryUuid,
        nome_tutor: "",
        email_tutor: "",
        quantidade_caes: caesJson.length,
        caes_json: caesJson,
        unidade_preferida: "nao_definida",
        servico_interesse: "nao_definido",
        origem_lead: "anuncio_whatsapp",
        origem_detalhada: "chat_n8n_teste",
        status_lead: "NOVO_LEAD",
        ultima_intencao: "",
        evento_sistema_atual: "",
        resumo_lead_json: resumoLead
      },

      config_bruna_modelo: {},
      criado_em_teste: nowIso
    }
  }
];

function parseMaybeJson(value, fallback) {
  if (value === undefined || value === null || value === "") return fallback;
  if (typeof value === "object") return value;

  try {
    return JSON.parse(value);
  } catch (e) {
    const text = String(value || "").trim();
    const match = text.match(/\{[\s\S]*\}/);

    if (match) {
      try {
        return JSON.parse(match[0]);
      } catch (e2) {}
    }

    return fallback;
  }
}

function clone(value) {
  return JSON.parse(JSON.stringify(value || {}));
}

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function normalizeEnum(value, allowed, fallback) {
  const v = String(value || "").trim();
  return allowed.includes(v) ? v : fallback;
}

function toBool(value) {
  if (value === true) return true;
  if (value === false) return false;
  if (value === 1) return true;
  if (value === 0) return false;

  const text = String(value || "").trim().toLowerCase();

  if (["1", "true", "sim", "yes", "t"].includes(text)) return true;
  if (["0", "false", "nao", "não", "no", "f"].includes(text)) return false;

  return false;
}

function toNumber(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function cleanText(value) {
  return String(value || "").trim();
}

function cleanArray(value) {
  if (!Array.isArray(value)) return [];
  return value;
}

function compactCandidatas(value) {
  const arr = cleanArray(value);

  return arr
    .filter(item => isObject(item))
    .map(item => ({
      raca_canonica: cleanText(item.raca_canonica),
      score: toNumber(item.score),
      potencial_dano: toBool(item.potencial_dano)
    }))
    .filter(item => item.raca_canonica)
    .slice(0, 5);
}

function compactRegrasRaca(value) {
  const regra = isObject(value) ? value : {};

  if (!Object.keys(regra).length) return {};

  return {
    raca_original: cleanText(regra.raca_original),
    raca_canonica: cleanText(regra.raca_canonica),

    porte_classificado: normalizeEnum(
      regra.porte_classificado,
      ["mini", "pequeno", "medio", "grande", "gigante", "nao_definido"],
      "nao_definido"
    ),

    aceita_auauzin: toBool(regra.aceita_auauzin),
    potencial_dano: toBool(regra.potencial_dano),

    raca_encontrada: toBool(regra.raca_encontrada),
    deve_confirmar_raca: toBool(regra.deve_confirmar_raca),

    status_raca: normalizeEnum(
      regra.status_raca,
      [
        "sem_raca_informada",
        "precisa_confirmar_raca",
        "bloqueado_potencial_dano",
        "raca_ok"
      ],
      "sem_raca_informada"
    ),

    decisao_raca_conclusiva: toBool(regra.decisao_raca_conclusiva),
    precisa_confirmacao_antes_decisao: toBool(regra.precisa_confirmacao_antes_decisao),

    pode_seguir_amaralina_por_raca: toBool(regra.pode_seguir_amaralina_por_raca),
    pode_seguir_auauzin_por_raca: toBool(regra.pode_seguir_auauzin_por_raca),

    motivo_raca: cleanText(regra.motivo_raca),
    escopo_decisao: "por_cao",

    score_match: toNumber(regra.score_match),
    tipo_match: cleanText(regra.tipo_match),
    qtd_racas_candidatas: toNumber(regra.qtd_racas_candidatas),
    score_top_1: toNumber(regra.score_top_1),
    score_top_2: toNumber(regra.score_top_2),
    gap_score: toNumber(regra.gap_score),
    nivel_confianca_raca: normalizeEnum(
      regra.nivel_confianca_raca,
      ["sem_raca", "baixa", "media", "alta"],
      ""
    ),

    racas_candidatas: compactCandidatas(regra.racas_candidatas)
  };
}

function normalizeDog(dog = {}) {
  return {
    nome: cleanText(dog.nome),
    idade_anos: cleanText(dog.idade_anos),
    idade_texto: cleanText(dog.idade_texto),
    raca: cleanText(dog.raca),
    raca_canonica: cleanText(dog.raca_canonica),

    porte: normalizeEnum(
      dog.porte,
      ["mini", "pequeno", "medio", "grande", "gigante", "nao_definido"],
      "nao_definido"
    ),

    sexo: normalizeEnum(
      dog.sexo,
      ["macho", "femea", "nao_informado"],
      "nao_informado"
    ),

    castrado: normalizeEnum(
      dog.castrado,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    no_cio: normalizeEnum(
      dog.no_cio,
      ["sim", "nao", "nao_se_aplica", "nao_informado"],
      "nao_informado"
    ),

    vacinas_ok: normalizeEnum(
      dog.vacinas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    antipulgas_ok: normalizeEnum(
      dog.antipulgas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    vermifugacao_ok: normalizeEnum(
      dog.vermifugacao_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    perfil_comportamental: normalizeEnum(
      dog.perfil_comportamental,
      [
        "nao_informado",
        "tranquilo",
        "sociavel",
        "seletivo",
        "reativo_leve",
        "reativo_alto",
        "agressivo",
        "indeterminado"
      ],
      "nao_informado"
    ),

    comportamento_observacoes: cleanText(dog.comportamento_observacoes),

    possui_relatorio_veterinario: normalizeEnum(
      dog.possui_relatorio_veterinario,
      ["sim", "nao", "nao_se_aplica", "nao_informado"],
      "nao_informado"
    ),

    observacoes: cleanText(dog.observacoes),
    regras_raca: compactRegrasRaca(dog.regras_raca)
  };
}

function stripDogDuplicates(ctx) {
  delete ctx.caes_json;
  delete ctx.regras_raca;
  delete ctx.consulta_raca_payload;

  if (ctx.memory) {
    delete ctx.memory.caes_json;
    delete ctx.memory.quantidade_caes;
    delete ctx.memory.resumo_lead_json;
    delete ctx.memory.resumo_interno_repasse_json;
    delete ctx.memory.payload_ultima_resposta_json;
  }

  if (ctx.inputs?.resumo_lead) {
    delete ctx.inputs.resumo_lead.caes_json;
    delete ctx.inputs.resumo_lead.quantidade_caes;
  }

  if (ctx.inputs?.resumo_interno_repasse) {
    delete ctx.inputs.resumo_interno_repasse.caes_json;
    delete ctx.inputs.resumo_interno_repasse.quantidade_caes;
  }

  return ctx;
}

const ctx = clone($("Normaliza Extrator e Prepara Raças").first().json);

const resultadoConsulta = parseMaybeJson($json.regras_raca, {
  caes_json: [],
  total_caes_consultados: 0,
  formato: "inputs.caes_json[].regras_raca"
});

const caesComRegras = Array.isArray(resultadoConsulta.caes_json)
  ? resultadoConsulta.caes_json
  : [];

const regrasPorIndex = new Map(
  caesComRegras.map((dog, index) => {
    const regra = isObject(dog.regras_raca) ? dog.regras_raca : {};
    const dogIndex = Number.isFinite(Number(regra.dog_index))
      ? Number(regra.dog_index)
      : index;

    return [dogIndex, dog];
  })
);

const caesOriginais = Array.isArray(ctx.inputs?.caes_json)
  ? ctx.inputs.caes_json
  : [];

const caesJson = caesOriginais.map((dog, index) => {
  const base = normalizeDog(dog);
  const enriquecido = regrasPorIndex.get(index);

  if (!enriquecido) return base;

  const regra = compactRegrasRaca(enriquecido.regras_raca);
  const out = { ...base, regras_raca: regra };

  if (regra.raca_encontrada && regra.status_raca !== "precisa_confirmar_raca") {
    if (regra.raca_canonica) {
      out.raca_canonica = regra.raca_canonica;
    }

    if (
      regra.porte_classificado &&
      regra.porte_classificado !== "nao_definido" &&
      (!out.porte || out.porte === "nao_definido")
    ) {
      out.porte = regra.porte_classificado;
    }
  }

  return normalizeDog(out);
});

ctx.inputs = ctx.inputs || {};
ctx.inputs.caes_json = caesJson;
ctx.inputs.quantidade_caes = caesJson.length;

ctx.inputs.regras_raca_meta = {
  total_caes_consultados: Number(resultadoConsulta.total_caes_consultados || caesJson.length || 0),
  formato: "inputs.caes_json[].regras_raca",
  com_baixa_confianca: caesJson.filter(
    dog => dog.regras_raca?.status_raca === "precisa_confirmar_raca"
  ).length,
  com_bloqueio_potencial_dano: caesJson.filter(
    dog => dog.regras_raca?.status_raca === "bloqueado_potencial_dano"
  ).length
};

ctx.debug_contexto = {
  ...(ctx.debug_contexto || {}),
  aplica_regras_raca_version: "v2_confianca_sem_hardcoded",
  total_caes_consultados: ctx.inputs.regras_raca_meta.total_caes_consultados,
  caes_com_baixa_confianca: ctx.inputs.regras_raca_meta.com_baixa_confianca,
  caes_com_bloqueio_potencial_dano: ctx.inputs.regras_raca_meta.com_bloqueio_potencial_dano,
  regras_raca_resumo: caesJson.map((dog, index) => ({
    index,
    nome: dog.nome,
    raca: dog.raca,
    raca_canonica: dog.raca_canonica,
    status_raca: dog.regras_raca?.status_raca || "",
    nivel_confianca_raca: dog.regras_raca?.nivel_confianca_raca || "",
    score_match: dog.regras_raca?.score_match || 0,
    gap_score: dog.regras_raca?.gap_score || 0,
    qtd_racas_candidatas: dog.regras_raca?.qtd_racas_candidatas || 0
  }))
};

return [{ json: stripDogDuplicates(ctx) }];

const ctx = $json || {};

const inputs = ctx.inputs || {};
const lead = ctx.lead || {};
const chatwoot = ctx.chatwoot || {};
const message = ctx.message || {};
const memory = ctx.memory || {};
const debugContext = ctx.debug_context || ctx.debug_contexto || {};

const queryWarnings = [];

function sql(value) {
  if (value === undefined || value === null || value === "") return "NULL";
  if (typeof value === "boolean") return value ? "1" : "0";
  if (typeof value === "number" && Number.isFinite(value)) return String(value);

  return "'" + String(value)
    .replace(/\\/g, "\\\\")
    .replace(/'/g, "''") + "'";
}

function sqlText(value) {
  if (value === undefined || value === null) return "NULL";

  return "'" + String(value)
    .replace(/\\/g, "\\\\")
    .replace(/'/g, "''") + "'";
}

function sqlJson(value) {
  const text = JSON.stringify(value ?? {});
  return "CAST(" + sqlText(text) + " AS JSON)";
}

function enumOrNull(value) {
  return value ? sql(value) : "NULL";
}

function toBool(value) {
  if (value === true) return true;
  if (value === false) return false;
  if (value === 1) return true;
  if (value === 0) return false;

  const text = String(value || "").trim().toLowerCase();

  if (["1", "true", "sim", "yes", "t"].includes(text)) return true;
  if (["0", "false", "nao", "não", "no", "f"].includes(text)) return false;

  return false;
}

function safeNumber(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function cleanString(value) {
  if (value === undefined || value === null) return "";
  if (typeof value === "object") {
    try {
      return JSON.stringify(value);
    } catch (e) {
      return "";
    }
  }
  return String(value).trim();
}

function parseMaybeJson(value, fallback) {
  if (value === undefined || value === null || value === "") return fallback;
  if (typeof value === "object") return value;

  try {
    return JSON.parse(value);
  } catch (e) {
    return fallback;
  }
}

function parseArray(value) {
  const parsed = parseMaybeJson(value, []);
  return Array.isArray(parsed) ? parsed : [];
}

function enumValue(value, allowed, fallback, path = "") {
  const v = cleanString(value);

  if (allowed.includes(v)) return v;

  if (v && path) {
    queryWarnings.push({
      path,
      raw: v,
      result: fallback,
      reason: "enum_invalido_usado_fallback"
    });
  }

  return fallback;
}

function sqlDateOrNull(value, path = "") {
  const v = cleanString(value);

  if (!v) return "NULL";

  if (/^\d{4}-\d{2}-\d{2}$/.test(v)) {
    return sql(v);
  }

  if (/^\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2}$/.test(v)) {
    return sql(v);
  }

  queryWarnings.push({
    path,
    raw: v,
    result: "NULL",
    reason: "data_nao_iso_descartada_para_evitar_erro_mysql"
  });

  return "NULL";
}

function normalizeMessages(value) {
  const arr = parseArray(value)
    .map(cleanString)
    .filter(Boolean);

  if (arr.length > 4) {
    queryWarnings.push({
      path: "inputs.mensagens_resposta",
      raw: arr.length,
      result: arr.length,
      reason: "mais_de_4_mensagens_sem_corte_automatico"
    });
  }

  return arr;
}

function stripDogCopies(obj = {}) {
  const out = { ...(obj || {}) };

  delete out.caes_json;
  delete out.quantidade_caes;
  delete out.regras_raca;

  delete out.caes;
  delete out.cao_nome;
  delete out.cao_idade_anos;
  delete out.cao_idade_texto;
  delete out.cao_raca;
  delete out.cao_porte;
  delete out.cao_sexo;
  delete out.cao_castrado;
  delete out.cao_no_cio;
  delete out.cao_vacinas_ok;
  delete out.cao_antipulgas_ok;
  delete out.cao_vermifugacao_ok;
  delete out.cao_perfil_comportamental;
  delete out.cao_comportamento_observacoes;
  delete out.possui_relatorio_veterinario;
  delete out.cao_sociavel;
  delete out.cao_reativo;

  return out;
}

function normalizeResumoLead(value = {}) {
  const resumo = stripDogCopies(value);

  const comprovanteRecebido = toBool(resumo.comprovante_recebido || inputs.comprovante_recebido);

  return {
    tutor_nome: cleanString(resumo.tutor_nome || lead.sender_name || memory.nome_tutor),
    tutor_telefone: cleanString(resumo.tutor_telefone || lead.phone || memory.phone),
    email_tutor: cleanString(resumo.email_tutor || memory.email_tutor),

    unidade_preferida: enumValue(
      resumo.unidade_preferida || inputs.unidade_preferida || memory.unidade_preferida,
      ["amaralina", "auauzin_patamares", "nao_definida"],
      "nao_definida",
      "resumo_lead.unidade_preferida"
    ),

    servico_interesse: enumValue(
      resumo.servico_interesse || inputs.servico_interesse || memory.servico_interesse,
      ["creche", "hotel", "creche_e_hotel", "visita", "nao_definido"],
      "nao_definido",
      "resumo_lead.servico_interesse"
    ),

    periodo_desejado: cleanString(resumo.periodo_desejado || inputs.periodo_desejado || memory.periodo_desejado),
    data_desejada: cleanString(resumo.data_desejada || inputs.data_desejada || memory.data_desejada),
    data_checkin_desejada: cleanString(resumo.data_checkin_desejada || inputs.data_checkin_desejada || memory.data_checkin_desejada),
    data_checkout_desejada: cleanString(resumo.data_checkout_desejada || inputs.data_checkout_desejada || memory.data_checkout_desejada),

    origem_lead: enumValue(
      resumo.origem_lead || memory.origem_lead || "anuncio_whatsapp",
      ["organico", "anuncio_whatsapp", "formulario_instagram", "indicacao", "site", "google_ads", "outro"],
      "outro",
      "resumo_lead.origem_lead"
    ),

    origem_detalhada: cleanString(resumo.origem_detalhada || memory.origem_detalhada || ctx.origem_execucao || "chat_n8n_teste"),

    comprovante_recebido: comprovanteRecebido,

    tipo_comprovante: comprovanteRecebido
      ? enumValue(
          resumo.tipo_comprovante || inputs.tipo_comprovante || memory.tipo_comprovante,
          ["imagem", "pdf", "print_banco", "nao_informado"],
          "nao_informado",
          "resumo_lead.tipo_comprovante"
        )
      : "nao_informado",

    arquivo_comprovante_referencia: cleanString(
      resumo.arquivo_comprovante_referencia ||
      inputs.arquivo_comprovante_referencia ||
      memory.arquivo_comprovante_referencia
    ),

    data_hora_avaliacao: "",
    data_hora_pre_reserva: "",
    pre_reserva_criada: false,

    responsavel_humano: toBool(inputs.deve_repassar_humano) ? "Flavia" : "",

    observacoes: cleanString(resumo.observacoes)
  };
}

function normalizeResumoRepasse(value = {}, resumo = {}) {
  const repasse = stripDogCopies(value);
  const deveRepassar = toBool(inputs.deve_repassar_humano);

  return {
    repassar_para: deveRepassar ? "Flavia" : "",
    motivo: deveRepassar ? cleanString(inputs.motivo_repasse || repasse.motivo) : "",

    tutor_nome: cleanString(repasse.tutor_nome || resumo.tutor_nome),
    tutor_telefone: cleanString(repasse.tutor_telefone || resumo.tutor_telefone),

    unidade_preferida: enumValue(
      repasse.unidade_preferida || resumo.unidade_preferida,
      ["amaralina", "auauzin_patamares", "nao_definida"],
      "nao_definida",
      "resumo_interno_repasse.unidade_preferida"
    ),

    servico_interesse: enumValue(
      repasse.servico_interesse || resumo.servico_interesse,
      ["creche", "hotel", "creche_e_hotel", "visita", "nao_definido"],
      "nao_definido",
      "resumo_interno_repasse.servico_interesse"
    ),

    data_hora_avaliacao: "",

    comprovante_recebido: resumo.comprovante_recebido === true,
    tipo_comprovante: resumo.tipo_comprovante || "nao_informado",

    observacoes: cleanString(repasse.observacoes || resumo.observacoes)
  };
}

const caesJson = parseArray(inputs.caes_json);
const quantidadeCaes = caesJson.length;

const resumo = normalizeResumoLead(inputs.resumo_lead || {});
const repasse = normalizeResumoRepasse(inputs.resumo_interno_repasse || {}, resumo);

const mensagensResposta = normalizeMessages(inputs.mensagens_resposta);
let shouldReply = ctx.should_reply !== false && mensagensResposta.length > 0;

let motivoBloqueioEnvio = cleanString(ctx.motivo_bloqueio_envio);

if (!shouldReply && !motivoBloqueioEnvio) {
  motivoBloqueioEnvio = mensagensResposta.length ? "should_reply_false" : "sem_mensagem_resposta_valida";
}

const chatOutput = shouldReply
  ? mensagensResposta.join("\n\n").trim()
  : "";

const statusLead = enumValue(
  inputs.status_lead || "NOVO_LEAD",
  [
    "NOVO_LEAD",
    "COLETANDO_DADOS",
    "QUALIFICANDO",
    "PRE_REPROVADO",
    "APTO_PARA_AVALIACAO",
    "AGUARDANDO_PAGAMENTO",
    "COMPROVANTE_RECEBIDO",
    "TRANSFERIDO_FLAVIA",
    "ENCERRADO_NAO_PERFIL",
    "ENCERRADO_SEM_RESPOSTA",
    "ENCERRADO"
  ],
  "NOVO_LEAD",
  "status_lead"
);

const ultimaIntencao = enumValue(
  inputs.ultima_intencao || "",
  [
    "",
    "INTERESSE_CRECHE",
    "INTERESSE_HOTEL",
    "PEDIU_VALOR",
    "PEDIU_LOCALIZACAO",
    "PEDIU_VISITA",
    "INFORMOU_DADOS_CAO",
    "INFORMOU_DADOS_TUTOR",
    "ACEITOU_AVALIACAO",
    "RECEBEU_PIX",
    "ENVIOU_COMPROVANTE",
    "PEDIU_HUMANO",
    "MACHO_NAO_CASTRADO",
    "RACA_POTENCIAL_DANO",
    "URGENCIA_FERIADO",
    "OBJECAO_PRECO",
    "SUMIU"
  ],
  "",
  "ultima_intencao"
);

const eventoSistema = enumValue(
  inputs.evento_sistema || "",
  [
    "",
    "FORMULARIO_RECEBIDO",
    "GUIA_ENVIADO",
    "PIX_SOLICITADO",
    "ANEXO_RECEBIDO",
    "COMPROVANTE_IDENTIFICADO",
    "REPASSE_FLAVIA",
    "FOLLOWUP_DISPARADO",
    "CONVERSA_ENCERRADA"
  ],
  "",
  "evento_sistema"
);

const apto = enumValue(
  inputs.apto_para_avaliacao || "",
  ["sim", "nao", "caso_cinzento", "pendente"],
  statusLead === "APTO_PARA_AVALIACAO"
    ? "sim"
    : statusLead === "ENCERRADO_NAO_PERFIL"
      ? "nao"
      : "pendente",
  "apto_para_avaliacao"
);

const statusPagamento =
  resumo.comprovante_recebido === true
    ? "validacao_humana_pendente"
    : (
        toBool(inputs.deve_solicitar_pagamento) ||
        eventoSistema === "PIX_SOLICITADO" ||
        statusLead === "AGUARDANDO_PAGAMENTO"
      )
      ? "aguardando_pagamento"
      : enumValue(
          inputs.status_pagamento || memory.status_pagamento || "nao_solicitado",
          [
            "nao_solicitado",
            "aguardando_pagamento",
            "comprovante_recebido",
            "validacao_humana_pendente",
            "aprovado_humano",
            "negado_humano",
            "estornado",
            "cancelado"
          ],
          "nao_solicitado",
          "status_pagamento"
        );

const guiaEnviado =
  toBool(inputs.guia_enviado) ||
  toBool(memory.guia_enviado) ||
  eventoSistema === "GUIA_ENVIADO";

const runMode = enumValue(
  ctx.run_mode || "sandbox",
  ["prod", "sandbox", "shadow"],
  "sandbox",
  "run_mode"
);

const promptVersion = cleanString(
  ctx.prompt_version ||
  inputs.versao_regras_negocio ||
  "bruna_v9_guard_raca_confianca"
);

const contratoPayload = "v9_inputs_caes_unico";

const accountId = safeNumber(chatwoot.account_id);
const contactId = safeNumber(chatwoot.contact_id);
const conversationId = safeNumber(chatwoot.conversation_id);
const messageId = cleanString(message.current_message_id || chatwoot.message_id);
const lastProcessedMessageId = safeNumber(message.current_message_id || chatwoot.message_id);

const phone = cleanString(lead.phone || memory.phone || resumo.tutor_telefone);
const chatHistoryUuid = cleanString(lead.chat_history_uuid || memory.chat_history_uuid);

const outputBruna = {
  status_lead: statusLead,
  ultima_intencao: ultimaIntencao,
  evento_sistema: eventoSistema,
  mensagens_resposta: shouldReply ? mensagensResposta : [],
  resumo_lead: resumo,
  proxima_acao: cleanString(inputs.proxima_acao || "aguardar_resposta_do_lead"),
  deve_repassar_humano: toBool(inputs.deve_repassar_humano),
  motivo_repasse: toBool(inputs.deve_repassar_humano) ? cleanString(inputs.motivo_repasse) : "",
  deve_enviar_guia: toBool(inputs.deve_enviar_guia),
  deve_solicitar_pagamento: toBool(inputs.deve_solicitar_pagamento),
  deve_consultar_agenda: false,
  deve_criar_pre_reserva: false,
  deve_encerrar_conversa: toBool(inputs.deve_encerrar_conversa),
  resumo_interno_repasse: repasse
};

const payloadUltimaResposta = {
  output: outputBruna,
  should_reply: shouldReply,
  motivo_bloqueio_envio: motivoBloqueioEnvio,
  warnings: [
    ...(Array.isArray(debugContext.warnings) ? debugContext.warnings : []),
    ...(Array.isArray(debugContext.race_guard?.warnings) ? debugContext.race_guard.warnings : []),
    ...queryWarnings
  ],
  debug_context: debugContext
};

const origemJson = {
  origem_execucao: ctx.origem_execucao || "",
  sessionId: ctx.sessionId || "",
  run_mode: runMode,
  should_reply: shouldReply,
  motivo_bloqueio_envio: motivoBloqueioEnvio
};

const inputDebugJson = {
  message,
  inputs: {
    ...inputs,
    resumo_lead: resumo,
    resumo_interno_repasse: repasse,
    caes_json: caesJson,
    quantidade_caes: quantidadeCaes
  },
  debug_context: debugContext,
  query_warnings: queryWarnings
};

const outputDebugJson = {
  output: outputBruna,
  chatOutput,
  should_reply: shouldReply,
  motivo_bloqueio_envio: motivoBloqueioEnvio,
  query_warnings: queryWarnings
};

const motivoPreReprovacao = cleanString(inputs.motivo_pre_reprovacao);

