  deveSolicitarPagamento = false;
  deveEncerrarConversa = false;
  deveRepassarHumano = false;
  motivoRepasse = "";
  proximaAcao = "aguardar_confirmacao_raca";
}

if (!deveRepassarHumano && eventoSistema === "REPASSE_FLAVIA") {
  warnings.push({
    path: "evento_sistema",
    raw: eventoSistema,
    result: "",
    reason: "repasse_removido_sem_deve_repassar_humano"
  });

  eventoSistema = "";
}

resumoLead.responsavel_humano = deveRepassarHumano ? "Flavia" : "";

resumoInternoRepasse = normalizeResumoRepasse(
  previousRepasse,
  brunaResumoRepasseForNormalize,
  resumoLead,
  deveRepassarHumano,
  motivoRepasse
);

const currentJoined = mensagensResposta.join(" ");
const similarityToLast = similarity(currentJoined, lastBrunaMessage);

if (similarityToLast >= 0.82 && mensagensResposta.length) {
  warnings.push({
    path: "mensagens_resposta",
    raw: similarityToLast,
    result: similarityToLast,
    reason: "resposta_parecida_com_ultima_mensagem_bruna"
  });
}

if (hasRepeatedConfirmation(mensagensResposta, lastBrunaMessage)) {
  warnings.push({
    path: "mensagens_resposta",
    raw: "obrigada/obrigado por confirmar",
    result: "warning",
    reason: "repeticao_de_validacao_robotica"
  });
}

const normalizedBase = {
  status_lead: statusLead,
  ultima_intencao: ultimaIntencao,
  evento_sistema: eventoSistema,

  mensagens_resposta: mensagensResposta,

  resumo_lead: resumoLead,

  proxima_acao: proximaAcao,

  deve_repassar_humano: deveRepassarHumano,
  motivo_repasse: motivoRepasse,

  deve_enviar_guia: deveEnviarGuia,
  deve_solicitar_pagamento: deveSolicitarPagamento,

  deve_consultar_agenda: false,
  deve_criar_pre_reserva: false,
  deve_encerrar_conversa: deveEncerrarConversa,

  resumo_interno_repasse: resumoInternoRepasse
};

if (!hasConversationContinuation(mensagensResposta, normalizedBase)) {
  warnings.push({
    path: "mensagens_resposta",
    raw: mensagensResposta[mensagensResposta.length - 1] || "",
    result: "warning",
    reason: "possivel_fechamento_sem_continuacao"
  });
}

let shouldReply = base.should_reply !== false;
let motivoBloqueioEnvio = base.should_reply === false
  ? firstFilled(base.motivo_bloqueio_envio, "should_reply_false_entrada")
  : "";

if (!mensagensResposta.length) {
  shouldReply = false;
  motivoBloqueioEnvio = motivoBloqueioEnvio || "sem_mensagem_resposta_valida";
}

if (unwrapped.parse_error === true) {
  shouldReply = false;
  motivoBloqueioEnvio = "erro_parse_saida_bruna";
}

if (humanoAssumiu) {
  shouldReply = false;
  motivoBloqueioEnvio = "humano_assumiu";
}

if (!shouldReply) {
  normalizedBase.mensagens_resposta = [];
  normalizedBase.deve_enviar_guia = false;
  normalizedBase.deve_solicitar_pagamento = false;
  normalizedBase.deve_repassar_humano = false;
  normalizedBase.motivo_repasse = "";
  normalizedBase.deve_consultar_agenda = false;
  normalizedBase.deve_criar_pre_reserva = false;
  normalizedBase.evento_sistema = "";

  if (motivoBloqueioEnvio === "humano_assumiu") {
    normalizedBase.proxima_acao = "nao_responder_humano_assumiu";
  }

  if (motivoBloqueioEnvio === "erro_parse_saida_bruna") {
    normalizedBase.proxima_acao = "nao_responder_erro_parse_saida_bruna";
  }

  if (motivoBloqueioEnvio === "sem_mensagem_resposta_valida") {
    normalizedBase.proxima_acao = "nao_responder_sem_mensagem_valida";
  }

  if (motivoBloqueioEnvio === "should_reply_false_entrada") {
    normalizedBase.proxima_acao = "nao_responder_bloqueado_entrada";
  }
}

const statusPagamento = resumoLead.comprovante_recebido
  ? "validacao_humana_pendente"
  : normalizedBase.deve_solicitar_pagamento
    ? "aguardando_pagamento"
    : enumValue(
        previousInputs.status_pagamento,
        [
          "nao_solicitado",
          "aguardando_pagamento",
          "comprovante_recebido",
          "validacao_humana_pendente",
          "aprovado_humano",
          "negado_humano",
          "estornado",
          "cancelado"
        ],
        "nao_solicitado",
        "status_pagamento"
      );

const normalizedInputs = {
  ...previousInputs,

  status_lead: normalizedBase.status_lead,
  ultima_intencao: normalizedBase.ultima_intencao,
  evento_sistema: normalizedBase.evento_sistema,

  apto_para_avaliacao: enumValue(
    brunaOverride.apto_para_avaliacao || bruna.apto_para_avaliacao || previousInputs.apto_para_avaliacao,
    ["sim", "nao", "caso_cinzento", "pendente"],
    normalizedBase.status_lead === "APTO_PARA_AVALIACAO"
      ? "sim"
      : normalizedBase.status_lead === "ENCERRADO_NAO_PERFIL"
        ? "nao"
        : previousInputs.apto_para_avaliacao || "pendente",
    "apto_para_avaliacao"
  ),

  motivo_pre_reprovacao: firstFilled(
    brunaOverride.motivo_pre_reprovacao,
    bruna.motivo_pre_reprovacao,
    previousInputs.motivo_pre_reprovacao
  ),

  status_pagamento: statusPagamento,

  comprovante_recebido: resumoLead.comprovante_recebido,
  tipo_comprovante: resumoLead.tipo_comprovante,
  arquivo_comprovante_referencia: resumoLead.arquivo_comprovante_referencia,

  pre_reserva_criada: false,
  data_hora_avaliacao: "",
  data_hora_pre_reserva: "",

  quantidade_caes: quantidadeCaes,
  caes_json: caesJson,

  resumo_lead: resumoLead,
  resumo_interno_repasse: resumoInternoRepasse,

  proxima_acao: normalizedBase.proxima_acao,

  deve_repassar_humano: normalizedBase.deve_repassar_humano,
  motivo_repasse: normalizedBase.motivo_repasse,

  deve_enviar_guia: normalizedBase.deve_enviar_guia,
  deve_solicitar_pagamento: normalizedBase.deve_solicitar_pagamento,
  deve_consultar_agenda: false,
  deve_criar_pre_reserva: false,
  deve_encerrar_conversa: normalizedBase.deve_encerrar_conversa,

  mensagens_resposta: shouldReply ? normalizedBase.mensagens_resposta : [],

  diagnostico_crm: {
    ...(isObject(previousInputs.diagnostico_crm) ? previousInputs.diagnostico_crm : {}),
    humano_assumiu: humanoAssumiu
  },

  bruna_system_guard: brunaSystemGuard,
  bruna_override: brunaOverride
};

delete normalizedInputs.resumo_lead.caes_json;
delete normalizedInputs.resumo_lead.quantidade_caes;
delete normalizedInputs.resumo_interno_repasse.caes_json;
delete normalizedInputs.resumo_interno_repasse.quantidade_caes;

const debugContext = {
  normaliza_bruna_version: "v10_aplica_bruna_override",
  parse_error: unwrapped.parse_error === true,
  parse_error_message: unwrapped.raw_parsed?.__parse_error_message || "",
  received_keys: Object.keys(bruna || {}),
  quantidade_caes: quantidadeCaes,
  mensagens_resposta_count: mensagensResposta.length,
  mensagens_resposta_maior_que_4: mensagensResposta.length > 4,
  similarity_to_last_bruna_message: similarityToLast,
  humano_assumiu: humanoAssumiu,
  should_reply: shouldReply,
  motivo_bloqueio_envio: motivoBloqueioEnvio,

  bruna_override: {
    aplicado: hasBrunaOverride,
    keys: Object.keys(brunaOverride || {}),
    motivo_loop: brunaSystemGuard?.motivo_loop || "",
    anti_loop_acionado: brunaSystemGuard?.anti_loop_acionado === true,
    deve_forcar_humano: brunaSystemGuard?.deve_forcar_humano === true,
    deve_forcar_apto: brunaSystemGuard?.deve_forcar_apto === true
  },

  race_guard: {
    has_pending_race_confirmation: guardRaca.hasPendingRaceConfirmation,
    pending_count: guardRaca.pendingRaceDogs.length,
    has_conclusive_breed_block: guardRaca.hasConclusiveBreedBlock,
    blocked_count: guardRaca.blockedRaceDogs.length,
    ignorado_por_override: hasBrunaOverride === true
  },

  warnings
};

return [
  {
    json: {
      inputs: normalizedInputs,

      message: base.message || {},
      chatwoot: base.chatwoot || {},
      lead: base.lead || {},
      memory: cleanMemory(base.memory),

      config_bruna: base.config_bruna || {},

      agent_name: base.agent_name || "Bruna",
      should_reply: shouldReply,
      motivo_bloqueio_envio: motivoBloqueioEnvio,

      opcoes: base.opcoes || {},

      run_mode: base.run_mode || "prod",
      prompt_version:
        base.prompt_version ||
        previousInputs.versao_regras_negocio ||
        "v10_aplica_bruna_override",

      raw_bruna_output: rawOutput,

      debug_context: debugContext
    }
  }
];

