function parseMaybeJson(value, fallback) {
  if (value === undefined || value === null || value === "") return fallback;
  if (typeof value === "object") return value;

  const text = String(value || "")
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();

  try {
    return JSON.parse(text);
  } catch (e) {
    const match = text.match(/\{[\s\S]*\}/);
    if (match) {
      try {
        return JSON.parse(match[0]);
      } catch (e2) {}
    }
  }

  return fallback;
}

function clone(value) {
  return JSON.parse(JSON.stringify(value || {}));
}

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function cleanText(value) {
  return String(value || "").trim();
}

function publicFacingText(value) {
  return cleanText(value)
    .replace(/pitua[cç]u/gi, "Patamares")
    .replace(/nunca use Patamares\.?/gi, "")
    .replace(/não use Patamares\.?/gi, "")
    .replace(/nao use Patamares\.?/gi, "")
    .replace(/\s{2,}/g, " ")
    .trim();
}

function norm(value) {
  return publicFacingText(value)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .trim();
}

function normalizeEnum(value, allowed, fallback) {
  const v = cleanText(value);
  return allowed.includes(v) ? v : fallback;
}

function meaningful(value) {
  const v = norm(value);

  return Boolean(
    v &&
    ![
      "nao_informado",
      "nao informado",
      "não informado",
      "nao_definido",
      "nao definido",
      "não definido",
      "nao_se_aplica",
      "nao se aplica",
      "não se aplica"
    ].includes(v)
  );
}

function emptyDog() {
  return {
    nome: "",
    idade_anos: "",
    idade_texto: "",
    raca: "",
    raca_canonica: "",
    porte: "nao_definido",
    sexo: "nao_informado",
    castrado: "nao_informado",
    no_cio: "nao_informado",
    vacinas_ok: "nao_informado",
    antipulgas_ok: "nao_informado",
    vermifugacao_ok: "nao_informado",
    perfil_comportamental: "nao_informado",
    comportamento_observacoes: "",
    possui_relatorio_veterinario: "nao_informado",
    observacoes: "",
    regras_raca: {}
  };
}

function normalizeDog(dog = {}) {
  const out = {
    ...emptyDog(),

    nome: publicFacingText(dog.nome),
    idade_anos: cleanText(dog.idade_anos),
    idade_texto: publicFacingText(dog.idade_texto),
    raca: publicFacingText(dog.raca),
    raca_canonica: publicFacingText(dog.raca_canonica),

    porte: normalizeEnum(
      dog.porte,
      ["mini", "pequeno", "medio", "grande", "gigante", "nao_definido"],
      "nao_definido"
    ),

    sexo: normalizeEnum(
      dog.sexo,
      ["macho", "femea", "nao_informado"],
      "nao_informado"
    ),

    castrado: normalizeEnum(
      dog.castrado,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    no_cio: normalizeEnum(
      dog.no_cio,
      ["sim", "nao", "nao_se_aplica", "nao_informado"],
      "nao_informado"
    ),

    vacinas_ok: normalizeEnum(
      dog.vacinas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    antipulgas_ok: normalizeEnum(
      dog.antipulgas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    vermifugacao_ok: normalizeEnum(
      dog.vermifugacao_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    perfil_comportamental: normalizeEnum(
      dog.perfil_comportamental,
      [
        "nao_informado",
        "tranquilo",
        "sociavel",
        "seletivo",
        "reativo_leve",
        "reativo_alto",
        "agressivo",
        "indeterminado"
      ],
      "nao_informado"
    ),

    comportamento_observacoes: publicFacingText(dog.comportamento_observacoes),

    possui_relatorio_veterinario: normalizeEnum(
      dog.possui_relatorio_veterinario,
      ["sim", "nao", "nao_se_aplica", "nao_informado"],
      "nao_informado"
    ),

    observacoes: publicFacingText(dog.observacoes),
    regras_raca: isObject(dog.regras_raca) ? dog.regras_raca : {}
  };

  if (out.sexo === "macho") {
    out.no_cio = "nao_se_aplica";
  }

  return out;
}

function normalizeDogs(value) {
  const parsed = parseMaybeJson(value, []);
  if (!Array.isArray(parsed)) return [];

  return parsed
    .filter(dog => isObject(dog))
    .map(normalizeDog)
    .filter(dog => hasDogIdentity(dog));
}

function hasDogIdentity(dog = {}) {
  return Boolean(
    meaningful(dog.nome) ||
    meaningful(dog.raca) ||
    meaningful(dog.raca_canonica) ||
    meaningful(dog.idade_anos) ||
    meaningful(dog.idade_texto) ||
    ["macho", "femea"].includes(cleanText(dog.sexo))
  );
}

function dogKey(dog = {}) {
  const nome = norm(dog.nome);
  if (nome) return `nome:${nome}`;

  return [
    `raca:${norm(dog.raca_canonica || dog.raca)}`,
    `idade:${norm(dog.idade_anos || dog.idade_texto)}`,
    `sexo:${norm(dog.sexo)}`
  ].join("|");
}

function mergeDog(base = {}, patch = {}) {
  const out = normalizeDog(base);
  const incoming = normalizeDog(patch);

  const fields = [
    "nome",
    "idade_anos",
    "idade_texto",
    "raca",
    "raca_canonica",
    "porte",
    "sexo",
    "castrado",
    "no_cio",
    "vacinas_ok",
    "antipulgas_ok",
    "vermifugacao_ok",
    "perfil_comportamental",
    "comportamento_observacoes",
    "possui_relatorio_veterinario",
    "observacoes"
  ];

  for (const field of fields) {
    const next = incoming[field];
    const current = out[field];

    if (!meaningful(next)) continue;

    if (!meaningful(current)) {
      out[field] = next;
      continue;
    }

    if (
      [
        "nome",
        "idade_anos",
        "idade_texto",
        "raca",
        "raca_canonica",
        "porte",
        "sexo",
        "castrado",
        "no_cio",
        "vacinas_ok",
        "antipulgas_ok",
        "vermifugacao_ok",
        "perfil_comportamental",
        "possui_relatorio_veterinario"
      ].includes(field)
    ) {
      out[field] = next;
    }

    if (field === "comportamento_observacoes" || field === "observacoes") {
      out[field] = next;
    }
  }

  // As regras de raça sempre serão recalculadas depois da extração.
  out.regras_raca = {};

  return normalizeDog(out);
}

function mergeDogs(baseDogs = [], patchDogs = []) {
  const base = normalizeDogs(baseDogs);
  const patch = normalizeDogs(patchDogs);

  if (!patch.length) return base;
  if (!base.length) return patch.map(dog => ({ ...dog, regras_raca: {} }));

  const result = [...base];
  const index = new Map();

  result.forEach((dog, i) => {
    index.set(dogKey(dog), i);
  });

  for (const dog of patch) {
    const key = dogKey(dog);

    if (index.has(key)) {
      const pos = index.get(key);
      result[pos] = mergeDog(result[pos], dog);
      continue;
    }

    // Se há só um cão conhecido e o patch também tem só um cão, normalmente é complemento do mesmo cão.
    if (result.length === 1 && patch.length === 1) {
      result[0] = mergeDog(result[0], dog);
      continue;
    }

    index.set(key, result.length);
    result.push({ ...dog, regras_raca: {} });
  }

  return result.map(normalizeDog);
}

function unwrapExtractor(raw) {
  let parsed = parseMaybeJson(raw, {});

  if (typeof parsed.text === "string") {
    parsed = parseMaybeJson(parsed.text, {});
  }

  if (typeof parsed.output === "string") {
    parsed = parseMaybeJson(parsed.output, {});
  }

  if (isObject(parsed.output)) {
    parsed = {
      ...parsed,
      ...parsed.output
    };
    delete parsed.output;
  }

  return isObject(parsed) ? parsed : {};
}

function applyResumoPatch(resumoAtual = {}, patch = {}) {
  const resumo = isObject(resumoAtual) ? { ...resumoAtual } : {};
  const p = isObject(patch) ? patch : {};

  const fields = [
    "servico_interesse",
    "periodo_desejado",
    "data_desejada",
    "data_checkin_desejada",
    "data_checkout_desejada",
    "observacoes"
  ];

  for (const field of fields) {
    if (meaningful(p[field])) {
      resumo[field] = publicFacingText(p[field]);
    }
  }

  delete resumo.caes_json;
  delete resumo.quantidade_caes;

  return resumo;
}

function normalizeSearchValue(value) {
  const text = publicFacingText(value);

  if (!text) return "";

  const normalized = norm(text);

  if (
    normalized === "nao_informado" ||
    normalized === "nao informado" ||
    normalized === "não informado" ||
    normalized === "indefinido" ||
    normalized === "nao_definido" ||
    normalized === "não definido"
  ) {
    return "";
  }

  return text;
}

function normalizeDogForBreedLookup(dog = {}, index = 0) {
  const raca = normalizeSearchValue(dog.raca);
  const racaCanonica = normalizeSearchValue(dog.raca_canonica);
  const racaBusca = racaCanonica || raca;

  return {
    dog_index: index,
    nome: publicFacingText(dog.nome),
    idade_anos: cleanText(dog.idade_anos),
    idade_texto: publicFacingText(dog.idade_texto),

    raca,
    raca_canonica: racaCanonica,
    raca_busca: racaBusca,

    porte: cleanText(dog.porte) || "nao_definido",
    sexo: cleanText(dog.sexo) || "nao_informado",
    castrado: cleanText(dog.castrado) || "nao_informado",
    no_cio: cleanText(dog.no_cio) || "nao_informado",
    vacinas_ok: cleanText(dog.vacinas_ok) || "nao_informado",
    antipulgas_ok: cleanText(dog.antipulgas_ok) || "nao_informado",
    vermifugacao_ok: cleanText(dog.vermifugacao_ok) || "nao_informado",
    perfil_comportamental: cleanText(dog.perfil_comportamental) || "nao_informado",
    comportamento_observacoes: publicFacingText(dog.comportamento_observacoes),
    possui_relatorio_veterinario: cleanText(dog.possui_relatorio_veterinario) || "nao_informado",
    observacoes: publicFacingText(dog.observacoes)

    // regras_raca não vai neste payload.
    // A consulta Postgres deve recalcular a regra.
  };
}

function normalizeDogsForBreedLookup(value) {
  const dogs = normalizeDogs(value);

  return dogs.map((dog, index) => normalizeDogForBreedLookup(dog, index));
}

function cleanResumoLead(value = {}) {
  const resumo = isObject(value) ? { ...value } : {};

  delete resumo.caes_json;
  delete resumo.quantidade_caes;

  return resumo;
}

// Contexto completo vem do node anterior ao extrator.
const ctx = clone($("Monta Contexto Bruna Solo").first().json);

// Saída do Extrator Estado Lead chega neste node como $json.
const extractor = unwrapExtractor($json);

ctx.inputs = ctx.inputs || {};
ctx.inputs.resumo_lead = ctx.inputs.resumo_lead || {};

const caesAtuais = Array.isArray(ctx.inputs.caes_json)
  ? ctx.inputs.caes_json
  : [];

const caesPatch = Array.isArray(extractor.caes_json)
  ? extractor.caes_json
  : [];

function hasPendingBreedConfirmation(dog = {}) {
  const regra = isObject(dog.regras_raca) ? dog.regras_raca : {};

  return (
    regra.status_raca === "precisa_confirmar_raca" ||
    regra.deve_confirmar_raca === true ||
    regra.precisa_confirmacao_antes_decisao === true ||
    regra.nivel_confianca_raca === "baixa"
  );
}

function isBreedConfirmationState(ctx, dogs = []) {
  const action = norm(ctx.inputs?.proxima_acao || "");

  if (
    action === "aguardar_confirmacao_raca" ||
    action === "confirmar_raca" ||
    action === "confirmar_raca_ambigua"
  ) {
    return true;
  }

  return dogs.some(hasPendingBreedConfirmation);
}

function isShortUsefulReply(text) {
  const value = norm(text);
  if (!value) return false;

  const words = value.split(/\s+/).filter(Boolean);

  if (words.length < 1 || words.length > 4) return false;
  if (value.length > 50) return false;

  const nonBreedReplies = new Set([
    "sim",
    "nao",
    "não",
    "ok",
    "certo",
    "isso",
    "nao sei",
    "não sei"
  ]);

  return !nonBreedReplies.has(value);
}

function getPendingBreedDogIndex(dogs = []) {
  const pendingIndexes = dogs
    .map((dog, index) => ({ dog, index }))
    .filter(item => hasPendingBreedConfirmation(item.dog));

  if (pendingIndexes.length === 1) {
    return pendingIndexes[0].index;
  }

  if (dogs.length === 1) {
    return 0;
  }

  return -1;
}

function hasUsefulBreedPatch(dogs = []) {
  return normalizeDogs(dogs).some(dog => {
    const raca = norm(dog.raca);
    const racaCanonica = norm(dog.raca_canonica);

    return Boolean(raca || racaCanonica);
  });
}

function buildBreedConfirmationPatch(ctx, caesAtuais, caesPatch) {
  const currentText = publicFacingText(ctx.message?.content || ctx.chatInput || "");

  if (!isBreedConfirmationState(ctx, caesAtuais)) return caesPatch;
  if (!isShortUsefulReply(currentText)) return caesPatch;

  const dogIndex = getPendingBreedDogIndex(caesAtuais);
  if (dogIndex < 0) return caesPatch;

  const dog = caesAtuais[dogIndex] || {};
  const regra = isObject(dog.regras_raca) ? dog.regras_raca : {};

  const baseRace = publicFacingText(regra.raca_original || dog.raca || "");
  if (!baseRace) return caesPatch;

  const composedRace = `${baseRace} ${currentText}`.trim();

  const patchDog = {
    ...dog,
    raca: composedRace,
    raca_canonica: "",
    regras_raca: {},
    observacoes: publicFacingText(
      [dog.observacoes, `Confirmação de raça recebida: ${currentText}`]
        .filter(Boolean)
        .join(" | ")
    )
  };

  const normalizedPatch = normalizeDogs(caesPatch);

  // Se o extrator já trouxe uma raça útil, não sobrescreve.
  if (hasUsefulBreedPatch(normalizedPatch)) {
    return normalizedPatch.map((item, index) => {
      if (index !== dogIndex && normalizedPatch.length > 1) return item;
      return {
        ...item,
        raca_canonica: "",
        regras_raca: {}
      };
    });
  }

  // Se o extrator trouxe patch sem raça útil, substitui pelo patch correto.
  if (normalizedPatch.length) {
    const result = [...normalizedPatch];
    result[0] = {
      ...result[0],
      ...patchDog
    };
    return result;
  }

  return [patchDog];
}

