function compactDogName(dog = {}) {
  const nome = cleanString(dog.nome);
  return nome ? `do ${nome}` : "dele";
}

function dedupeCandidates(candidates = []) {
  const seen = new Set();
  const out = [];

  for (const item of parseArray(candidates)) {
    const name = cleanString(item.raca_canonica || item.nome || item.raca);
    if (!name) continue;

    const key = normalizeText(name);
    if (!key || seen.has(key)) continue;

    seen.add(key);
    out.push(name);

    if (out.length >= 3) break;
  }

  return out;
}

function buildRaceConfirmMessage(dog = {}) {
  const regra = dog.regras_raca || {};
  const original = cleanString(regra.raca_original || dog.raca || "a raça informada");
  const candidates = dedupeCandidates(regra.racas_candidatas);

  if (candidates.length >= 2) {
    const list =
      candidates.length === 2
        ? `${candidates[0]} ou ${candidates[1]}`
        : `${candidates.slice(0, -1).join(", ")} ou ${candidates[candidates.length - 1]}`;

    return `Pra eu não cadastrar errado: qual é a raça exata ${compactDogName(dog)}? Para “${original}”, apareceram possibilidades como ${list}.`;
  }

  return `Pra eu não cadastrar errado: qual é a raça exata ${compactDogName(dog)}? O nome “${original}” precisa ser confirmado antes de eu te orientar sobre os próximos passos.`;
}

function raceGuard(caesJson = []) {
  const dogs = parseArray(caesJson);

  const pending = [];
  const blocked = [];

  for (const dog of dogs) {
    const regra = isObject(dog.regras_raca) ? dog.regras_raca : {};
    const status = cleanString(regra.status_raca);
    const confidence = cleanString(regra.nivel_confianca_raca);

    const needsConfirm =
      status === "precisa_confirmar_raca" ||
      toBool(regra.deve_confirmar_raca) ||
      toBool(regra.precisa_confirmacao_antes_decisao) ||
      confidence === "baixa";

    const isBlocked =
      status === "bloqueado_potencial_dano" &&
      !needsConfirm &&
      toBool(regra.decisao_raca_conclusiva);

    if (needsConfirm) {
      pending.push(dog);
      continue;
    }

    if (isBlocked) {
      blocked.push(dog);
    }
  }

  return {
    hasPendingRaceConfirmation: pending.length > 0,
    pendingRaceDogs: pending,
    hasConclusiveBreedBlock: blocked.length > 0,
    blockedRaceDogs: blocked
  };
}

