function hasPendingBreedConfirmation(dog = {}) {
  const regra = isObject(dog.regras_raca) ? dog.regras_raca : {};

  return (
    regra.status_raca === "precisa_confirmar_raca" ||
    regra.deve_confirmar_raca === true ||
    regra.precisa_confirmacao_antes_decisao === true ||
    regra.nivel_confianca_raca === "baixa"
  );
}

function isBreedConfirmationState(ctx, dogs = []) {
  const action = norm(ctx.inputs?.proxima_acao || "");

  if (
    action === "aguardar_confirmacao_raca" ||
    action === "confirmar_raca" ||
    action === "confirmar_raca_ambigua"
  ) {
    return true;
  }

  return dogs.some(hasPendingBreedConfirmation);
}

function isShortUsefulReply(text) {
  const value = norm(text);
  if (!value) return false;

  const words = value.split(/\s+/).filter(Boolean);

  if (words.length < 1 || words.length > 4) return false;
  if (value.length > 50) return false;

  const nonBreedReplies = new Set([
    "sim",
    "nao",
    "não",
    "ok",
    "certo",
    "isso",
    "nao sei",
    "não sei"
  ]);

  return !nonBreedReplies.has(value);
}

function getPendingBreedDogIndex(dogs = []) {
  const pendingIndexes = dogs
    .map((dog, index) => ({ dog, index }))
    .filter(item => hasPendingBreedConfirmation(item.dog));

  if (pendingIndexes.length === 1) {
    return pendingIndexes[0].index;
  }

  if (dogs.length === 1) {
    return 0;
  }

  return -1;
}

function hasUsefulBreedPatch(dogs = []) {
  return normalizeDogs(dogs).some(dog => {
    const raca = norm(dog.raca);
    const racaCanonica = norm(dog.raca_canonica);

    return Boolean(raca || racaCanonica);
  });
}

function buildBreedConfirmationPatch(ctx, caesAtuais, caesPatch) {
  const currentText = publicFacingText(ctx.message?.content || ctx.chatInput || "");

  if (!isBreedConfirmationState(ctx, caesAtuais)) return caesPatch;
  if (!isShortUsefulReply(currentText)) return caesPatch;

  const dogIndex = getPendingBreedDogIndex(caesAtuais);
  if (dogIndex < 0) return caesPatch;

  const dog = caesAtuais[dogIndex] || {};
  const regra = isObject(dog.regras_raca) ? dog.regras_raca : {};

  const baseRace = publicFacingText(regra.raca_original || dog.raca || "");
  if (!baseRace) return caesPatch;

  const composedRace = `${baseRace} ${currentText}`.trim();

  const patchDog = {
    ...dog,
    raca: composedRace,
    raca_canonica: "",
    regras_raca: {},
    observacoes: publicFacingText(
      [dog.observacoes, `Confirmação de raça recebida: ${currentText}`]
        .filter(Boolean)
        .join(" | ")
    )
  };

  const normalizedPatch = normalizeDogs(caesPatch);

  // Se o extrator já trouxe uma raça útil, não sobrescreve.
  if (hasUsefulBreedPatch(normalizedPatch)) {
    return normalizedPatch.map((item, index) => {
      if (index !== dogIndex && normalizedPatch.length > 1) return item;
      return {
        ...item,
        raca_canonica: "",
        regras_raca: {}
      };
    });
  }

  // Se o extrator trouxe patch sem raça útil, substitui pelo patch correto.
  if (normalizedPatch.length) {
    const result = [...normalizedPatch];
    result[0] = {
      ...result[0],
      ...patchDog
    };
    return result;
  }

  return [patchDog];
}

const caesPatchEfetivo = buildBreedConfirmationPatch(ctx, caesAtuais, caesPatch);
const caesMesclados = mergeDogs(caesAtuais, caesPatchEfetivo);

ctx.inputs.caes_json = caesMesclados;
ctx.inputs.quantidade_caes = caesMesclados.length;

ctx.inputs.resumo_lead = applyResumoPatch(
  ctx.inputs.resumo_lead,
  extractor.resumo_lead_patch
);

ctx.inputs.turn_signals = isObject(extractor.turn_signals)
  ? extractor.turn_signals
  : {};

ctx.inputs.precisa_responder_preco = ctx.inputs.turn_signals.pediu_preco === true;
ctx.inputs.precisa_responder_localizacao = ctx.inputs.turn_signals.pediu_localizacao === true;
ctx.inputs.precisa_responder_visita_material = ctx.inputs.turn_signals.pediu_visita === true;

// Espelha alguns campos úteis fora do resumo para compatibilidade com prompts/nodes seguintes.
ctx.inputs.servico_interesse =
  ctx.inputs.resumo_lead.servico_interesse ||
  ctx.inputs.servico_interesse ||
  "nao_definido";

ctx.inputs.periodo_desejado =
  ctx.inputs.resumo_lead.periodo_desejado ||
  ctx.inputs.periodo_desejado ||
  "";

ctx.inputs.data_desejada =
  ctx.inputs.resumo_lead.data_desejada ||
  ctx.inputs.data_desejada ||
  "";

ctx.inputs.data_checkin_desejada =
  ctx.inputs.resumo_lead.data_checkin_desejada ||
  ctx.inputs.data_checkin_desejada ||
  "";

ctx.inputs.data_checkout_desejada =
  ctx.inputs.resumo_lead.data_checkout_desejada ||
  ctx.inputs.data_checkout_desejada ||
  "";

// Prepara payload para consulta de raças no Postgres.
const caesParaConsulta = normalizeDogsForBreedLookup(ctx.inputs.caes_json);

const warnings = [];

for (const dog of caesParaConsulta) {
  if (!dog.raca_busca) {
    warnings.push({
      dog_index: dog.dog_index,
      nome: dog.nome,
      warning: "cao_sem_raca_para_consulta"
    });
  }
}

ctx.consulta_raca_payload = {
  phone: ctx.lead?.phone || ctx.memory?.phone || "",
  quantidade_caes: caesParaConsulta.length,
  caes_json: caesParaConsulta,
  resumo_lead: cleanResumoLead(ctx.inputs?.resumo_lead),
  run_mode: ctx.run_mode || "sandbox",
  origem_execucao: ctx.origem_execucao || "chat_n8n_teste"
};

if (warnings.length) {
  ctx.consulta_raca_payload.warnings = warnings;
}

ctx.extrator_estado = {
  caes_extraidos: caesPatch.length,
  caes_apos_merge: caesMesclados.length,
  resumo_lead_patch: isObject(extractor.resumo_lead_patch) ? extractor.resumo_lead_patch : {},
  turn_signals: ctx.inputs.turn_signals,
  warnings: Array.isArray(extractor.warnings) ? extractor.warnings : [],
  raw_text: typeof $json.text === "string" ? $json.text : ""
};

ctx.debug_contexto = {
  ...(ctx.debug_contexto || {}),
  normaliza_extrator_prepara_racas_version: "v1",
  caes_antes_patch: caesAtuais.length,
  caes_extraidos_patch: caesPatchEfetivo.length,
  race_confirmation_patch_applied: JSON.stringify(caesPatchEfetivo) !== JSON.stringify(caesPatch),
  caes_depois_patch: caesMesclados.length,
  quantidade_caes_para_consulta: caesParaConsulta.length,
  warnings_consulta_raca: warnings
};

return [{ json: ctx }];

const item = $json;

function norm(v) {
  return String(v ?? '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/\p{Diacritic}/gu, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function onlyDigits(v) {
  return String(v ?? '').replace(/\D/g, '');
}

function getCaes() {
  if (Array.isArray(item.inputs?.caes_json)) return item.inputs.caes_json;
  if (Array.isArray(item.caes_json)) return item.caes_json;
  if (Array.isArray(item.consulta_raca_payload?.caes_json)) return item.consulta_raca_payload.caes_json;
  return [];
}

function hasValue(v) {
  const s = String(v ?? '').trim();
  return s !== '' && s !== 'nao_informado' && s !== 'nao_definido';
}

function isRealDog(cao) {
  return (
    hasValue(cao.nome) ||
    hasValue(cao.idade_anos) ||
    hasValue(cao.idade_texto) ||
    hasValue(cao.raca) ||
    hasValue(cao.raca_canonica) ||
    ['macho', 'femea'].includes(cao.sexo)
  );
}

function isEmptyDog(cao) {
  return !isRealDog(cao);
}

function questionTopic(text) {
  const t = norm(text);

  if (/(raca|raça|buldog|bulldog|spitz|salsicha|dachshund|porte)/.test(t)) return 'raca';
  if (/(idade|anos|meses|sexo|macho|femea|fêmea)/.test(t)) return 'dados_basicos';
  if (/(vacina|vacinacao|vacinação|antipulga|anti pulga|vermifug|v10|tosse|antirrabica|antirrábica)/.test(t)) return 'sanitario';
  if (/(convive|convivencia|convivência|outros caes|outros cães|reativ|comport|late|morde|avanca|avança)/.test(t)) return 'comportamento';
  if (/(frequencia|frequência|vezes por semana|quantas vezes|segunda|terça|terca|quarta|quinta|sexta|sabado|sábado)/.test(t)) return 'frequencia_creche';
  if (/(diaria|diária|hospedagem|hotel|check-in|checkin|check-out|checkout|periodo|período|datas|data)/.test(t)) return 'periodo_hotel';
  if (/(avaliacao|avaliação|taxa|pagamento|pix|comprovante)/.test(t)) return 'avaliacao_pagamento';
  if (/(relatorio|relatório|veterinario|veterinário)/.test(t)) return 'relatorio_veterinario';

  return 'outro';
}

function extractBrunaMessagesFromHistory(history) {
  const lines = String(history ?? '').split('\n');
  return lines
    .filter(l => /\]\s*Bruna:/i.test(l))
    .map(l => l.replace(/^.*?\]\s*Bruna:\s*/i, '').trim())
    .filter(Boolean);
}

function countRecentTopicRepeats(topic, messages) {
  if (!topic || topic === 'outro') return 0;
  return messages
    .slice(-8)
    .filter(m => questionTopic(m) === topic)
    .length;
}

function leadComplainedAboutRepeat(text) {
  const t = norm(text);
  return /(ja respondi|ja falei|voce ja perguntou|vc ja perguntou|de novo|novamente|acabei de falar|ja disse|esta em loop|ta em loop|loop)/.test(t);
}

function isFrequencyOnly(text) {
  const t = norm(text);
  return /^(\d+x|uma vez|duas vezes|tres vezes|três vezes|quatro vezes|cinco vezes|segunda|terca|terça|quarta|quinta|sexta|sabado|sábado|segunda a sexta|segunda a quinta|segunda e quinta|segunda quarta e sexta|toda semana|semanal)$/i.test(t);
}

function isHotelPeriod(text) {
  const t = norm(text);
  return /(\d{1,2}\s*a\s*\d{1,2}|de\s*\d{1,2}\s*a\s*\d{1,2}|check|hospedagem|hotel|sao joao|são joão|feriado|janeiro|fevereiro|marco|março|abril|maio|junho|julho|agosto|setembro|outubro|novembro|dezembro)/.test(t);
}

function parseSimplePeriodDays(text) {
  const t = norm(text);
  const m = t.match(/(?:de\s*)?(\d{1,2})\s*a\s*(\d{1,2})/);
  if (!m) return null;

  const start = Number(m[1]);
  const end = Number(m[2]);

  if (!Number.isFinite(start) || !Number.isFinite(end)) return null;
  if (start <= 0 || end <= 0 || end <= start) return null;

  return {
    start_day: start,
    end_day: end,
    diarias: end - start
  };
}

function normalizeFrequency(text) {
  const t = norm(text);

  if (/(^1x|uma vez)/.test(t)) return '1x por semana';
  if (/(^2x|duas vezes|segunda e quinta)/.test(t)) return '2x por semana';
  if (/(^3x|tres vezes|três vezes|segunda quarta e sexta|segunda, quarta e sexta)/.test(t)) return '3x por semana';
  if (/(^4x|quatro vezes|segunda a quinta)/.test(t)) return '4x por semana';
  if (/(^5x|cinco vezes|segunda a sexta)/.test(t)) return '5x por semana';

  return '';
}

function dogIsEligibleForEvaluation(cao) {
  const regras = cao.regras_raca || {};
  const statusRaca = regras.status_raca || '';

  const hasBasic =
    hasValue(cao.nome) &&
    (hasValue(cao.idade_anos) || hasValue(cao.idade_texto)) &&
    (hasValue(cao.raca) || hasValue(cao.raca_canonica)) &&
    ['macho', 'femea'].includes(cao.sexo);

  const hasSanitario =
    cao.vacinas_ok === 'sim' &&
    cao.antipulgas_ok === 'sim' &&
    cao.vermifugacao_ok === 'sim';

  const hasComportamento =
    hasValue(cao.perfil_comportamental) &&
    cao.perfil_comportamental !== 'nao_informado';

  const racaOk =
    statusRaca === 'raca_ok' ||
    statusRaca === '' ||
    statusRaca == null;

  const machoAdultoNaoCastrado =
    cao.sexo === 'macho' &&
    Number(String(cao.idade_anos ?? '').replace(',', '.')) >= 1 &&
    cao.castrado === 'nao';

  const racaBloqueada = statusRaca === 'bloqueado_potencial_dano';
  const racaPendente = statusRaca === 'precisa_confirmar_raca' || statusRaca === 'sem_raca_informada';

  return {
    ok: hasBasic && hasSanitario && hasComportamento && racaOk && !machoAdultoNaoCastrado && !racaBloqueada && !racaPendente,
    hasBasic,
    hasSanitario,
    hasComportamento,
    racaOk,
    machoAdultoNaoCastrado,
    racaBloqueada,
    racaPendente
  };
}

const currentLeadMessage = item.message?.content || item.chatInput || '';
const lastBruna = item.message?.last_bruna_message_before_current_block || '';
const history = item.message?.history_for_crm || '';
const brunaHistory = extractBrunaMessagesFromHistory(history);
const lastTopic = questionTopic(lastBruna);
const repeatCount = countRecentTopicRepeats(lastTopic, brunaHistory);
const leadComplained = leadComplainedAboutRepeat(currentLeadMessage);

let caes = getCaes().filter(cao => !isEmptyDog(cao));

const beforeCount = getCaes().length;
const afterCount = caes.length;

const removedEmptyDogs = beforeCount !== afterCount;

const currentIsFrequencyOnly = isFrequencyOnly(currentLeadMessage);
const frequency = normalizeFrequency(currentLeadMessage);

const currentIsHotelPeriod = isHotelPeriod(currentLeadMessage);
const hotelPeriod = parseSimplePeriodDays(currentLeadMessage);

const resumoLead = {
  ...(item.inputs?.resumo_lead || item.resumo_lead || {})
};

if (frequency) {
  resumoLead.servico_interesse = resumoLead.servico_interesse && resumoLead.servico_interesse !== 'nao_definido'
    ? resumoLead.servico_interesse
    : 'creche';

  resumoLead.periodo_desejado = resumoLead.periodo_desejado || frequency;
}

if (hotelPeriod) {
  resumoLead.servico_interesse = 'hotel';
  resumoLead.periodo_desejado = `período de ${hotelPeriod.start_day} a ${hotelPeriod.end_day}, ${hotelPeriod.diarias} diárias`;
}

const eligibilities = caes.map(dogIsEligibleForEvaluation);
const hasAnyEligible = eligibilities.some(e => e.ok);
const allKnownDogsEligible = caes.length > 0 && eligibilities.every(e => e.ok);

const serviceInterest =
  resumoLead.servico_interesse ||
  item.inputs?.servico_interesse ||
  item.servico_interesse ||
  'nao_definido';

const hasService = ['creche', 'hotel', 'creche_e_hotel'].includes(serviceInterest);

let guard = {
  anti_loop_acionado: false,
  motivo_loop: '',
  deve_forcar_humano: false,
  deve_forcar_apto: false,
  deve_bloquear_novo_cao_por_frequencia: false,
  removed_empty_dogs: removedEmptyDogs,
  topic_ultima_pergunta: lastTopic,
  repeat_count_topic: repeatCount,
  periodo_hotel_detectado: hotelPeriod || null,
  frequencia_detectada: frequency || ''
};

let override = {};

if (currentIsFrequencyOnly && caes.length >= 1) {
  guard.deve_bloquear_novo_cao_por_frequencia = true;
}

if (leadComplained || repeatCount >= 3) {
  guard.anti_loop_acionado = true;
  guard.deve_forcar_humano = true;
  guard.motivo_loop = leadComplained
    ? 'lead_reclamou_de_repeticao'
    : `pergunta_repetida_${lastTopic}_${repeatCount}_vezes`;

  override = {
    status_lead: 'TRANSFERIDO_FLAVIA',
    ultima_intencao: 'PEDIU_HUMANO',
    evento_sistema: 'REPASSE_FLAVIA',
    proxima_acao: 'repassar_para_humano_por_loop',
    deve_repassar_humano: true,
    motivo_repasse: 'Loop de atendimento detectado. A Bruna repetiu perguntas ou o lead sinalizou que já respondeu.',
    mensagens_resposta: [
      'Percebi que posso estar repetindo algumas perguntas por aqui. Para não travar seu atendimento, vou passar para uma pessoa especialista da equipe continuar com você em horário comercial.'
    ]
  };
}

if (!guard.deve_forcar_humano && hasService && allKnownDogsEligible) {
  guard.deve_forcar_apto = true;

  override = {
    status_lead: 'APTO_PARA_AVALIACAO',
    ultima_intencao: 'ACEITOU_AVALIACAO',
    evento_sistema: 'REPASSE_FLAVIA',
    apto_para_avaliacao: 'sim',
    proxima_acao: 'repassar_para_humano_explicar_avaliacao_e_proximos_passos',
    deve_repassar_humano: true,
    motivo_repasse: 'Lead chegou aos critérios mínimos para avaliação comportamental. Encaminhar para especialista humano orientar próximos passos.',
    deve_solicitar_pagamento: false,
    deve_consultar_agenda: false,
    deve_criar_pre_reserva: false,
    mensagens_resposta: [
      'Com essas informações, o próximo passo é a avaliação comportamental. Ela serve para a equipe entender com segurança se o cãozinho está apto para a rotina em grupo.',
      'Vou passar para uma pessoa especialista da equipe continuar com você e alinhar os próximos passos em horário comercial.'
    ]
  };
}

item.inputs = {
  ...(item.inputs || {}),
  caes_json: caes,
  quantidade_caes: caes.length,
  resumo_lead: resumoLead,
  bruna_system_guard: guard,
  bruna_override: override
};

item.caes_json = caes;
item.quantidade_caes = caes.length;
item.resumo_lead = resumoLead;
item.bruna_system_guard = guard;
item.bruna_override = override;

return item;
